import org.assertj.core.api.Assertions.assertThat
import org.junit.Test
import org.mockito.kotlin.doReturn
import org.mockito.kotlin.mock
import org.mockito.kotlin.whenever
import org.wordpress.android.R
import org.wordpress.android.models.ReaderTag
import org.wordpress.android.models.ReaderTagList
import org.wordpress.android.models.ReaderTagType
import org.wordpress.android.ui.compose.components.menu.dropdown.MenuElementData
import org.wordpress.android.ui.utils.UiString.UiStringRes
import org.wordpress.android.ui.utils.UiString.UiStringText
import org.wordpress.android.util.config.ReaderTagsFeedFeatureConfig

/**
 * Tests for custom lists display behavior in the Reader top bar menu.
 * This test file verifies that lists are displayed directly in the menu when there are 2 or fewer,
 * and in a submenu when there are more than 2 lists.
 */
class ReaderTopBarMenuHelperCustomListsDisplayTest {
    private val readerTagsFeedFeatureConfig: ReaderTagsFeedFeatureConfig = mock()
    private val helper = ReaderTopBarMenuHelper(
        readerTagsFeedFeatureConfig = readerTagsFeedFeatureConfig
    )

    @Test
    fun `GIVEN one custom list WHEN createMenu THEN list is displayed directly in menu root`() {
        whenever(readerTagsFeedFeatureConfig.isEnabled()).thenReturn(false)

        val tags = ReaderTagList().apply {
            add(mockDiscoverTag()) // item 0
            add(createCustomListTag("My List")) // item 1
        }

        val menu = helper.createMenu(tags)

        // Should contain a divider
        assertThat(menu).contains(MenuElementData.Divider)

        // Should NOT contain a submenu
        val customListsSubMenu = menu.findSubMenu()
        assertThat(customListsSubMenu).isNull()

        // The custom list should be a direct menu item
        val customListItem = menu.findSingleItem { it.text == UiStringText("My List") }
        assertThat(customListItem).isNotNull
        assertThat(customListItem!!.id).isEqualTo("1")
    }

    @Test
    fun `GIVEN two custom lists WHEN createMenu THEN lists are displayed directly in menu root`() {
        whenever(readerTagsFeedFeatureConfig.isEnabled()).thenReturn(false)

        val tags = ReaderTagList().apply {
            add(mockDiscoverTag()) // item 0
            add(createCustomListTag("First List")) // item 1
            add(createCustomListTag("Second List")) // item 2
        }

        val menu = helper.createMenu(tags)

        // Should contain a divider
        assertThat(menu).contains(MenuElementData.Divider)

        // Should NOT contain a submenu
        val customListsSubMenu = menu.findSubMenu()
        assertThat(customListsSubMenu).isNull()

        // Both custom lists should be direct menu items
        val firstListItem = menu.findSingleItem { it.text == UiStringText("First List") }
        assertThat(firstListItem).isNotNull
        assertThat(firstListItem!!.id).isEqualTo("1")

        val secondListItem = menu.findSingleItem { it.text == UiStringText("Second List") }
        assertThat(secondListItem).isNotNull
        assertThat(secondListItem!!.id).isEqualTo("2")
    }

    @Test
    fun `GIVEN three custom lists WHEN createMenu THEN lists are displayed in submenu`() {
        whenever(readerTagsFeedFeatureConfig.isEnabled()).thenReturn(false)

        val tags = ReaderTagList().apply {
            add(mockDiscoverTag()) // item 0
            add(createCustomListTag("First List")) // item 1
            add(createCustomListTag("Second List")) // item 2
            add(createCustomListTag("Third List")) // item 3
        }

        val menu = helper.createMenu(tags)

        // Should contain a divider
        assertThat(menu).contains(MenuElementData.Divider)

        // Should contain a submenu
        val customListsSubMenu = menu.findSubMenu()
        assertThat(customListsSubMenu).isNotNull
        assertThat(customListsSubMenu!!.text).isEqualTo(UiStringRes(R.string.reader_dropdown_menu_lists))

        // All three custom lists should be in the submenu
        val firstListItem = customListsSubMenu.children.findSingleItem { it.text == UiStringText("First List") }
        assertThat(firstListItem).isNotNull
        assertThat(firstListItem!!.id).isEqualTo("1")

        val secondListItem = customListsSubMenu.children.findSingleItem { it.text == UiStringText("Second List") }
        assertThat(secondListItem).isNotNull
        assertThat(secondListItem!!.id).isEqualTo("2")

        val thirdListItem = customListsSubMenu.children.findSingleItem { it.text == UiStringText("Third List") }
        assertThat(thirdListItem).isNotNull
        assertThat(thirdListItem!!.id).isEqualTo("3")

        // The custom lists should NOT be direct menu items
        val directFirstListItem = menu.findSingleItem { it.text == UiStringText("First List") }
        assertThat(directFirstListItem).isNull()
    }

    @Test
    fun `GIVEN two custom lists with other menu items WHEN createMenu THEN all items are created correctly`() {
        whenever(readerTagsFeedFeatureConfig.isEnabled()).thenReturn(false)

        val tags = ReaderTagList().apply {
            add(mockFollowingTag()) // item 0
            add(mockDiscoverTag()) // item 1
            add(mockSavedTag()) // item 2
            add(createCustomListTag("Travel")) // item 3
            add(createCustomListTag("Cooking")) // item 4
        }

        val menu = helper.createMenu(tags)

        // Check standard menu items exist
        val discoverItem = menu.findSingleItem { it.id == "1" }
        assertThat(discoverItem).isNotNull
        assertThat(discoverItem!!.text).isEqualTo(UiStringRes(R.string.reader_dropdown_menu_discover))

        val subscriptionsItem = menu.findSingleItem { it.id == "0" }
        assertThat(subscriptionsItem).isNotNull

        val savedItem = menu.findSingleItem { it.id == "2" }
        assertThat(savedItem).isNotNull

        // Check divider exists
        assertThat(menu).contains(MenuElementData.Divider)

        // Check custom lists are direct menu items (not in submenu)
        val travelItem = menu.findSingleItem { it.text == UiStringText("Travel") }
        assertThat(travelItem).isNotNull
        assertThat(travelItem!!.id).isEqualTo("3")

        val cookingItem = menu.findSingleItem { it.text == UiStringText("Cooking") }
        assertThat(cookingItem).isNotNull
        assertThat(cookingItem!!.id).isEqualTo("4")

        // Should NOT have a submenu
        val customListsSubMenu = menu.findSubMenu()
        assertThat(customListsSubMenu).isNull()
    }

    private fun List<MenuElementData>.findSingleItem(
        predicate: (MenuElementData.Item.Single) -> Boolean
    ): MenuElementData.Item.Single? {
        return find { it is MenuElementData.Item.Single && predicate(it) } as? MenuElementData.Item.Single
    }

    private fun List<MenuElementData>.findSubMenu(): MenuElementData.Item.SubMenu? {
        return find { it is MenuElementData.Item.SubMenu } as? MenuElementData.Item.SubMenu
    }

    private fun mockDiscoverTag(): ReaderTag {
        return mock {
            on { isDiscover } doReturn true
        }
    }

    private fun mockFollowingTag(): ReaderTag {
        return mock {
            on { isFollowedSites } doReturn true
        }
    }

    private fun mockSavedTag(): ReaderTag {
        return mock {
            on { isBookmarked } doReturn true
        }
    }

    private fun createCustomListTag(title: String): ReaderTag {
        return ReaderTag(
            title,
            title,
            title,
            "http://endpoint.com",
            ReaderTagType.CUSTOM_LIST
        )
    }
}
"}

